  } else if (casesAreContiguous(CasesB)) {
    ContiguousCases = &CasesB;
    ContiguousDest = DestB;
    OtherDest = DestA;
    WrappingOffset = APInt::getNullValue(CasesB[0]->getValue().getBitWidth());
  }

