{"command": "cd /app/data/auto-opt/utils/llvm-157113 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/Utils/SimplifyCFG.cpp 5739 5765
/// Check if cases form a contiguous range after adding some offset (wrapping).
/// Returns the offset (to be added) if yes, std::nullopt otherwise.
static std::optional<APInt> findWrappingOffsetForContiguous(SmallVectorImpl<ConstantInt *> &Cases) {
  if (Cases.empty())
    return std::nullopt;

  // Sort cases in descending order (same as casesAreContiguous)
  array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);

  // For a set to be "wrapping contiguous", adding offset should make it [0, N)
  // The offset is -min (where min is the smallest value)
  // After sorting descending, back() is the minimum
  APInt Min = Cases.back()->getValue();
  APInt Offset = -Min;

  // Verify all values are contiguous after adding offset
  APInt Prev = Cases.back()->getValue() + Offset; // Should be 0
  assert(Prev.isZero() && "Offset should make min value 0");

  for (size_t I = Cases.size() - 1; I > 0; --I) {
    APInt Curr = Cases[I]->getValue() + Offset;
    APInt Expected = Prev + 1;
    if (Curr != Expected)
      return std::nullopt;
    Prev = Curr;
  }

  return Offset;
}
CODEEOF
"}

